func hacktivityTrendRows(program string, sinceDays, limit int) ([]map[string]any, error) {
	db, err := openResearchStore()
	if err != nil {
		return nil, err
	}
	defer db.Close()
	hacks, err := listResourceObjects(db, "hacktivity", 100000)
	if err != nil {
		return nil, err
	}
	cutoff := time.Now().AddDate(0, 0, -sinceDays)
	type agg struct {
		count  int
		bounty float64
	}
	grouped := map[string]*agg{}
	for _, h := range hacks {
		if program != "" && stringField(h, "program.slug", "data.program.slug") != program {
			continue
		}
		if ts := parseFlexibleTime(stringField(h, "disclosed_at", "data.disclosed_at")); !ts.IsZero() && ts.Before(cutoff) {
			continue
		}
		cwe := stringField(h, "vulnerable_part", "data.vulnerable_part")
		if cwe == "" {
			cwe = "unknown"
		}
		if grouped[cwe] == nil {
			grouped[cwe] = &agg{}
		}
		grouped[cwe].count++
		grouped[cwe].bounty += floatField(h, "bounty_amount", "data.bounty_amount", "bounty")
	}
	var out []map[string]any
	for cwe, a := range grouped {
		avg := 0.0
		if a.count > 0 {
			avg = a.bounty / float64(a.count)
		}
		out = append(out, map[string]any{"cwe": cwe, "count": a.count, "avg_bounty": avg})
	}
	sort.Slice(out, func(i, j int) bool { return out[i]["count"].(int) > out[j]["count"].(int) })
	if len(out) > limit {
		out = out[:limit]
	}
	return out, nil
}
